const item = $input.first().json;
const now = new Date();
const kolkataParts = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Kolkata', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }).formatToParts(now).reduce((acc, part) => { if (part.type !== 'literal') acc[part.type] = part.value; return acc; }, {});
const id = `${kolkataParts.year}${kolkataParts.month}${kolkataParts.day}-${kolkataParts.hour}${kolkataParts.minute}${kolkataParts.second}`;
const timestamp = `${kolkataParts.year}-${kolkataParts.month}-${kolkataParts.day}T${kolkataParts.hour}:${kolkataParts.minute}:${kolkataParts.second}+05:30`;
return [{ json: { supabaseBody: { id, text_original: item.thought, text_published: null, status: 'pending', timestamp_ist: timestamp, seed: $('Build Gen Request 1').item.json.seed, score: item.score, reason: item.reason, suggestion: item.suggestion || null, round: 1, source: 'n8n', approved_at: null, approved_by_email: null, hidden_at: null } } }];

